  try {
    // בדיקה אם כבר קיים מורה עם אותו שם ומקצוע
    const existingTeacher = await Teacher.findOne({ name, subject });

    if (existingTeacher) {
      return { success: false, message: 'מורה עם שם ומקצוע זהים כבר קיים' };
    }

    // יצירת מורה חדש
    const newTeacher = new Teacher({ name, subject });
    await newTeacher.save();

    return { success: true, message: 'המורה נרשם בהצלחה', data: newTeacher };
