- נבדוק אם יש פרמטר ב-`req.body` או ב-`req.query` עם אחד השמות המותרים.  
- נסנן את המערך `items` כך שרק פריטים שערך השדה `salary` שלהם קטן או שווה לערך המותר יוחזרו.  
- נשתמש ב-`Number()` כדי להמיר את הערך למספר, ונטפל במקרה של ערך לא תקין.  
- נחזיר את התוצאה כ-JSON עם סטטוס 200.  
- נשתמש במערך `items` קבוע כנתוני בדיקה.

3. **קוד**
```javascript
const express = require('express');
const router = express.Router();

const items = [
  { id: 1, name: 'Alice', value: 100, salary: 5000, grade: 'A' },
  { id: 2, name: 'Bob', value: 200, salary: 4000, grade: 'B' },
  { id: 3, name: 'Charlie', value: 150, salary: 6000, grade: 'C' },
  { id: 4, name: 'Diana', value: 300, salary: 4500, grade: 'A' }
];

router.post('/filter', (req, res) => {
  const { body, query } = req;
  const possibleKeys = ['maxSalary', 'max_salary', 'salary', 'value', 'threshold'];

  let maxSalary = null;

  // Try to get the value from body first, then query
  for (const key of possibleKeys) {
    if (body.hasOwnProperty(key)) {
      maxSalary = Number(body[key]);
      break;
    } else if (query.hasOwnProperty(key)) {
      maxSalary = Number(query[key]);
      break;
    }
  }

  // Validate: must be a finite number
  if (maxSalary === null || !Number.isFinite(maxSalary)) {
    return res.status(400).json({ error: 'Invalid or missing filter parameter. Use one of: maxSalary, max_salary, salary, value, threshold' });
  }

  const filtered = items.filter(item => item.salary <= maxSalary);

  res.status(200).json(filtered);
});

module.exports = router;
```

4. **מלכודת נפוצה**  
שכיחות של שמות שונים לאותו פרמטר (`maxSalary`, `max_salary`, וכו') עלולה להוביל לשכיחות של `if/else` או `switch` מיותרים. חשוב להשתמש במערך של שמות אפשריים ולעבור עליו ב-`for` ליעילות.  
כמו כן, חשוב להמיר ל-`Number()` ולבדוק `Number.isFinite()` – לא רק `isNaN`, כי `Number(undefined)` מחזיר `NaN`, אך `isNaN(undefined)` מחזיר `true`, אבל `Number.isFinite(undefined)` מחזיר `false` – ולכן עדיף להשתמש ב-`isFinite` + בדיקה שהערך לא `null`.

5. **בדיקת תקינות**  
- שליחת `POST /filter` עם `body: { maxSalary: 5000 }` → אמורה להחזיר את Alice, Bob, Diana (3 פריטים).  
- שליחת `POST /filter` עם `query: { threshold: 4500 }` → אמורה להחזיר את Bob, Diana.

