import React, { useState } from 'react';

const FlightNumberInput = () => {
  const [flightNumber, setFlightNumber] = useState('');
  const [errors, setErrors] = useState([]);

  // הגדרת כללים לאימות
  const validationRules = [
    { 
      name: 'required', 
      test: (value) => value.trim().length > 0, 
      message: 'שדה מספר טיסה הוא חובה' 
    },
    { 
      name: 'length', 
      test: (value) => value.length <= 5, 
      message: 'הערך חייב להיות עד 5 תווים' 
    },
    { 
      name: 'regex', 
      test: (value) => /^[0-9]+$/.test(value), 
      message: 'הערך חייב להכיל ספרות בלבד' 
    },
    { 
      name: 'range', 
      test: (value) => {
        const num = parseInt(value, 10);
        return !isNaN(num) && num >= 100 && num <= 99999;
      },
      message: 'המספר חייב להיות בין 100 ל-99999' 
    }
  ];

  const handleChange = (e) => {
    const value = e.target.value;
    // מונע קלט מיותר: רק ספרות, עד 5 תווים
    if (/^\d*$/.test(value) && value.length <= 5) {
      setFlightNumber(value);
    }
  };

  const validate = () => {
    const newErrors = [];
    for (const rule of validationRules) {
      if (!rule.test(flightNumber)) {
        newErrors.push(rule.message);
      }
