  if (!Array.isArray(matrix) || !matrix.every(row => Array.isArray(row))) {
    throw new Error("הקלט חייב להיות מטריצה (מערך של מערכים)");
  }

  // פלט: מערך של אובייקטים
  const result = [];
  const counts = {};

  // טיפוס: נפריד את המטריצה למערך אחד
  const flat = matrix.flat();

  // בדיקה: כל ערך חייב להיות מספר
  for (const val of flat) {
    if (typeof val !== 'number' || Number.isNaN(val)) {
      throw new Error(`הערך ${val} אינו מספר תקף`);
    }
    counts[val] = (counts[val] || 0) + 1;
  }

  // יצירת אובייקטים לפלט
  for (const num in counts) {
    result.push({
      num: Number(num),
      count: counts[num]
    });
  }

  return result;
}

