// נמחק קובץ אם כבר קיים
const testFile = 'test_data.txt';
if (fs.existsSync(testFile)) fs.unlinkSync(testFile);

const fp = new FilePackage(testFile);
fp.appendContent('שלום');
fp.appendContent('עולם');

console.log(fp.searchWord('שלום')); // true
console.log(fp.searchWord('לא קיים')); // false

fp.rename('renamed.txt');
console.log(fs.existsSync('renamed.txt')); // true

const copied = fp.copy('copied.txt');
console.log(copied.searchWord('עולם')); // true
```

