async function safeAsyncOperation(data) {
  try {
    // דוגמה לפעולה שיכולה להיכשל: פארס של JSON
    const parsed = JSON.parse(data);
    return parsed;
  } catch (error) {
    console.error("שגיאה בפעולה האסינכרונית:", error.message);
    return { error: "Failed to parse input", rawInput: data };
  }
}

