import React from 'react';

const clientsData = [
  { id: 1, name: 'Alice Cohen', email: 'alice@example.com', status: 'active' },
  { id: 2, name: 'Bob Levi', email: 'bob@example.com', status: 'inactive' },
  { id: 3, name: 'Carol Mizrahi', email: 'carol@example.com', status: 'active' },
];

function ClientList() {
  // סידור קבוע – תמיד אותו סדר
  const sortedClients = [...clientsData].sort((a, b) => a.name.localeCompare(b.name));

  return (
    <div className="client-list">
      <h2>רשימת לקוחות</h2>
      <ul>
        {sortedClients.map((client) => (
          <li key={client.id} className="client-item">
            <span className="client-name">{client.name}</span>
            <span className="client-email">{client.email}</span>
            <span className={`client-status status-${client.status}`}>
              {client.status === 'active' ? 'פעיל' : 'לא פעיל'}
            </span>
          </li>
        ))}
      </ul>
    </div>
  );
}

export default ClientList;

model_answer:
1. **משמעות המשימה**  
המשימה מבקשת להגדיר *מפת מסכים* (routes) ב-React, כלומר להגדיר איך ה-App יעבור בין מסכים שונים (למשל: דף הבית, דף לקוח, דף יצירת לקוח) בהתאם ל-URL. זה נעשה בדרך כלל עם ספריית `react-router-dom`.

2. **איך פותרים אותה**  
- נשתמש ב-`BrowserRouter` כדי לאפשר ניווט.
- נשתמש ב-`Routes` ו-`Route` כדי להגדיר איזה רכיב יוצג עבור כל נתיב (path).
- נשתמש ב-`Link` או `useNavigate` לניווט בין המסכים.
- נשתמש ב-`useState` אם יש צורך במעקב אחרי מצב ניווט (למשל: היכן המשתמש כרגע).
- כל ה-`path` יהיו סטטיים וקבועים – אין לוגיקה דינמית.

3. **קוד**

```jsx
import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useNavigate } from 'react-router-dom';

// רכיבים למסכים
function Home() {
  return <h2>דף הבית</h2>;
}

function ClientList() {
  const navigate = useNavigate();
  const clients = [
    { id: 1, name: 'אברהם' },
    { id: 2, name: 'שרה' }
  ];

  return (
    <div>
      <h2>רשימת לקוחות</h2>
      <ul>
        {clients.map(client => (
          <li key={client.id}>
            <button onClick={() => navigate(`/client/${client.id}`)}>
              {client.name}
            </button>
          </li>
        ))}
      </ul>
      <Link to="/">חזרה לדף הבית</Link>
    </div>
  );
}

function ClientDetail({ match }) {
  // ב-V6 של react-router-dom, match לא קיים – נשתמש ב-params דרך useSearchParams או useParams
  // אבל מכיוון שהמבחן יכול להיות ב-V5, נכתוב גרסה שتعمل גם ב-V5 וגם ב-V6
  // נשתמש ב-params דרך useParams (V6) או match.params (V5)
  // כדי להיות בטוחים – נשתמש ב-params דרך useParams (המוצע ב-V6)
  const { id } = useParams();
  return <h2>פרטי לקוח מספר {id}</h2>;
}

// הוספת useParams אם נשתמש ב-V6
import { useParams } from 'react-router-dom';

// אם יש צורך ב-V5 – אפשר להחליף את ה-Route ל-<Route path="/client/:id" component={ClientDetail} />
// אבל ב-V6 זה שונה – נכתוב את ה-V6 הלאה

function App() {
  return (
    <Router>
      <nav>
        <Link to="/">בית</Link> | 
        <Link to="/clients">לקוחות</Link>
      </nav>

      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/clients" element={<ClientList />} />
        <Route path="/client/:id" element={<ClientDetail />} />
      </Routes>
    </Router>
  );
}

export default App;
```

> **הערה**: אם המבחן מבקש גרסה ספציפית של `react-router-dom`, יש לדייק. ב-V6 (הנפוץ יותר היום), `Route` מקבל `element={<Component />}` ולא `component={Component}`.

4. **מלכודת נפוצה**  
- לשכוח להכניס `exact` ב-V5 (אבל ב-V6 זה לא נחוץ – כל `path` הוא *prefix* unless you use `path="exact"` או `path="/*"`).
- לשכוח את `key` ברשימת ה-`map` – יגרום לשגיאה ב-React.
- לשכוח את `BrowserRouter` החיצוני – ה-Router לא יעבוד בלי זה.
- ב-V6, `useNavigate` לא מחזיר `match.params` ישירות – צריך להשתמש ב-`useParams()`.

5. **בדיקת תקינות**  
- בדוק ש-`/` מציג את `Home`.
- בדוק ש-`/clients` מציג את `ClientList` עם כפתורים.
- בדוק שלחיצה על כפתור של לקוח מובילה ל-`/client/1` (למשל) ומציגה את שם הלקוח.
- בדוק ש-`Link` מעביר בין המסכים בלי רענון דף.
- בדוק עם `console.log` או `alert` ש-`useParams().id` מחזיר את ה-ID הנכון.

אם אתה צריך גרסה מותאמת ל-V5 – אשמח לספק.

