  const [checked, setChecked] = useState(false);
  const [error, setError] = useState('');

  // הגדרת כללים לאמת את השדה
  const validationRules = {
    required: required,
    // length/range/regex לא רלוונטיים לבוליאני, אך אפשר לשלוט ב-true/false
    allowedValues: [true, false],
  };

  const validate = () => {
    if (validationRules.required && !checked) {
      setError('שדה רישיון למלגזה הוא חובה');
      return false;
    }
    setError('');
    return true;
  };

  const handleChange = (e) => {
    const value = e.target.checked;
    setChecked(value);
    // אפשר לנקות שגיאה בלחיצה
    if (error) setError('');
