  { id: 4, name: 'Diana', value: 90, salary: 4000, grade: 'C' }
];

// Helper: normalize key names to standard ones
function normalizeQuery(query) {
  const normalized = {};
  const aliases = {
    maxSalary: 'maxSalary',
    max_salary: 'maxSalary',
    salary: 'salary',
    value: 'value',
    threshold: 'value' // threshold is treated as value
  };

