      normalized.maxSalary = parseFloat(query[key]);
    } else if (standardKey === 'salary') {
      normalized.salary = parseFloat(query[key]);
    } else if (standardKey === 'value') {
      normalized.value = parseFloat(query[key]);
    }
  }

  return normalized;
}

