      2: { id: 2, name: "חמאה", price: 12.0 }
    };

    if (!mockData[id]) {
      throw new Error(`מוצר עם ID ${id} לא נמצא`);
    }

    // אם יש שגיאה בנתונים – נגרום להזרקה מודעת
    if (typeof mockData[id].price !== 'number') {
      throw new Error('מחיר לא תקין במוצר');
    }

    return mockData[id];
  } catch (error) {
    console.error(`שגיאה ב-getProductById ל-ID ${id}:`, error.message);
    return null; // או ערך ברירת מחדל אחר
