המשימה מבקשת לתכנן מבנה טופס (ב-React) שמתאים לדרישות – כלומר, להגדיר את השדות הנדרשים, הסוגים שלהם (input types), ולבנות רכיב React שמיישם אותם. יש לשים לב לדרישות של חוזה קוד חובה: state (useState), ערכים ו-onChange, אימות, וstructure תקנית (keys, map וכו').

2. **איך פותרים אותה**  
- נבחר דוגמה פשוטה וברורה – טופס רישום ללקוח (client form).  
- נגדיר שדות סטנדרטיים: שם, אימייל, טלפון, תאריך לידה, סטטוס (active/inactive).  
- נשתמש ב-`useState` לניהול ערכי השדות.  
- נשתמש ב-`onChange` לעדכון ה-state.  
- נוסיף אימות בסיסי (למשל, אימייל תקין, שדה חובה).  
- נשתמש ב-`key` אם יש דינמיקה (אפילו אם לא – חשוב להדגיש).  
- נשתמש ב-`type` תקין של input (text, email, tel, date, checkbox).  

3. **קוד**

```jsx
import React, { useState } from 'react';

const ClientForm = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    birthDate: '',
    isActive: true,
  });

  const [errors, setErrors] = useState({});

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }));

    // ניקוי שגיאה במשתנה הזה כשמתחילים לערוך
    if (errors[name]) {
      setErrors((prev) => {
        const newErrors = { ...prev };
        delete newErrors[name];
        return newErrors;
      });
    }
  };

  const validate = () => {
    const newErrors = {};
    if (!formData.name.trim()) newErrors.name = 'שם הוא שדה חובה';
    if (!formData.email.trim()) {
      newErrors.email = 'אימייל הוא שדה חובה';
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
      newErrors.email = 'אימייל לא תקין';
    }
    if (!formData.phone.trim()) newErrors.phone = 'טלפון הוא שדה חובה';
    if (!formData.birthDate) newErrors.birthDate = 'תאריך לידה הוא שדה חובה';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (validate()) {
      console.log('Form submitted:', formData);
      // כאן אפשר לשלוח לשרת או לעשות פעולה אחרת
    }
  };

  return (
    <form onSubmit={handleSubmit} style={{ maxWidth: '400px', margin: '0 auto' }}>
      <div>
        <label htmlFor="name">שם:</label>
        <input
          id="name"
          name="name"
          type="text"
          value={formData.name}
          onChange={handleChange}
          required
        />
        {errors.name && <span style={{ color: 'red' }}>{errors.name}</span>}
      </div>

      <div>
        <label htmlFor="email">אימייל:</label>
        <input
          id="email"
          name="email"
          type="email"
          value={formData.email}
          onChange={handleChange}
          required
        />
        {errors.email && <span style={{ color: 'red' }}>{errors.email}</span>}
      </div>

      <div>
        <label htmlFor="phone">טלפון:</label>
        <input
          id="phone"
          name="phone"
          type="tel"
          value={formData.phone}
          onChange={handleChange}
          required
        />
        {errors.phone && <span style={{ color: 'red' }}>{errors.phone}</span>}
      </div>

      <div>
        <label htmlFor="birthDate">תאריך לידה:</label>
        <input
          id="birthDate"
          name="birthDate"
          type="date"
          value={formData.birthDate}
          onChange={handleChange}
          required
        />
        {errors.birthDate && (
          <span style={{ color: 'red' }}>{errors.birthDate}</span>
        )}
      </div>

      <div>
        <label>
          <input
            name="isActive"
            type="checkbox"
            checked={formData.isActive}
            onChange={handleChange}
          />
          פעיל
        </label>
      </div>

      <button type="submit">שליחה</button>
    </form>
  );
};

export default ClientForm;
```

4. **מלכודת נפוצה**  
- לשכוח ללחוץ על `e.preventDefault()` ב-`handleSubmit` – זה גורם לרענון דף.  
- לא לנקות שגיאות במשתנה שמתעדכן – זה גורם לשגיאות להישאר גם אחרי תיקון.  
- לא להשתמש ב-`type="email"` או `type="tel"` – זה מקל על אימות ומשתמשים.  
- לשכוח לספק `key` אם יש דינ

