  try {
    // בדיקה ידנית אם כבר קיים (למשל אם לא משתמשים ב-unique: true)
    const existing = await Product.findOne({ id: productId }).exec();
    if (existing) {
      throw new Error(`Product with ID "${productId}" already exists`);
    }

    const product = new Product({ id: productId, name: productName });
    await product.save();
    return product;
  } catch (err) {
    if (err.code === 11000) {
