    await new Promise((resolve, reject) => {
      setTimeout(() => reject(new Error('תקלה בנתונים')), 100);
    });
    return { id: 1, title: 'test' };
  } catch (e) {
    return { id: -1, title: 'error' }; // ערך ברירת מחדל דטרמיניסטי
  }
}
```

