const mongoose = require('mongoose');

// הגדרת הסכימה
const userSchema = new mongoose.Schema({
  username: {
    type: String,
    required: true,
    unique: true, // שדה ייחודי
    trim: true,
    lowercase: true
  },
  email: {
    type: String,
    required: true,
    unique: true, // שדה ייחודי
    trim: true,
    lowercase: true
  },
  isActive: {
    type: Boolean,
    required: true,
    default: true
  }
}, {
  timestamps: true
});

// יצירת המודל
const User = mongoose.model('User', userSchema);

// דוגמה לשימוש עם טיפול בשגיאות
async function createUser(username, email, isActive = true) {
  try {
    const user = new User({ username, email, isActive });
    await user.save();
    return user;
  } catch (error) {
    if (error.name === 'MongoServerError' && error.code === 11000) {
      // שגיאה של שדה כפול
