const MelgazaForm = () => {
  const [melgaza, setMelgaza] = useState(false);
  const [error, setError] = useState('');

  // חוקי אימות
  const validationRules = {
    required: true,
    type: 'boolean',
  };

  const validate = () => {
    // חובה: חייב להיות מסומן (true)
    if (validationRules.required && melgaza === false) {
      setError('השדה "האם צריך מלגזה" הוא חובה.');
      return false;
    }
    // טיפוס: חייב להיות בוליאני
    if (typeof melgaza !== 'boolean') {
      setError('הערך חייב להיות בוליאני (true/false).');
      return false;
    }
    setError('');
    return true;
  };

  const handleChange = (e) => {
    setMelgaza(e.target.checked);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (validate()) {
      alert(`הmelgaza הוא: ${melgaza}`);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <label>
        <input
          type="checkbox"
          checked={melgaza}
          onChange={handleChange}
        />
        האם צריך מלגזה?
      </label>
      {error && <p style={{ color: 'red' }}>{error}</p>}
      <button type="submit">שלח</button>
    </form>
  );
};

export default MelgazaForm;
