            </button>
          </li>
        ))}
      </ul>
      <Link to="/create">יצירת לקוח חדש</Link>
    </div>
  );
}

// ה-App הראשי עם ה-routes
function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<ClientList />} />
        <Route path="/client/:id" element={<ClientDetail />} />
        <Route path="/create" element={<CreateClient />} />
      </Routes>
    </Router>
  );
}

export default App;
