      required: true,
      pattern: /^\d+$/, // רק ספרות
      minLength: 5,
      maxLength: 10
    },
    name: {
      required: true,
      minLength: 3,
      maxLength: 50
    },
    quantity: {
      required: false,
      min: 0,
      max: 1000
    }
  };

