          </ul>
        ) : (
          <p>אין לקוחות זמינים</p>
        )}
      </div>

      <button onClick={() => navigate('/')}>חזרה לדף הבית</button>

      <Modal
        isOpen={showModal}
        onClose={() => setShowModal(false)}
        message="שגיאה: לא נמצאו לקוחות במערכת"
      />
    </div>
  );
};

// ה-App הראשי עם מסارات
const App = () => (
  <Router>
    <Routes>
      <Route path="/" element={<Home />} />
      <Route path="/client" element={<ClientPage />} />
    </Routes>
  </Router>
);

export default App;
```

