const MOCK_CLIENTS = [
  { id: 11122, name: 'קופסא ירוקה', needsMelgaza: false },
  { id: 33445, name: 'משתמש בדיקה', needsMelgaza: true },
];

// רכיב ליצירת לקוח חדש (למשל: מסך יצירת לקוח)
function CreateClient() {
  const navigate = useNavigate();

  const handleCreate = () => {
    // בדיקת דטרמיניזם: תמיד יוצר את אותו לקוח (למשל: ID 99999)
    const newClient = { id: 99999, name: 'לקוח חדש', needsMelgaza: false };
    // נשמור ב-memory (בפועל אפשר לשלוף ב-state גלובלי או localStorage)
    // כאן פשוט נעבור למסך הלקוח החדש
    navigate(`/client/${newClient.id}`);
  };

  return (
    <div>
      <h2>יצירת לקוח חדש</h2>
      <button onClick={handleCreate}>צור לקוח (למשל: ID 99999)</button>
    </div>
  );
}

// רכיב להצגת פרטי לקוח
function ClientDetail({ clientId }) {
  const client = MOCK_CLIENTS.find(c => c.id === clientId);

  if (!client) {
    return <p>הלקוח לא נמצא.</p>;
  }

  return (
    <div style={{ border: '2px solid green', padding: '10px' }}>
      <h3>פרטי הלקוח</h3>
      <p><strong>שם:</strong> {client.name}</p>
      <p><strong>מזהה:</strong> {client.id}</p>
      <p><strong>צריך מלגזה:</strong> {client.needsMelgaza ? 'כן' : 'לא'}</p>
    </div>
  );
}

// דף הבית – מציג רשימת לקוחות
function ClientList() {
  const navigate = useNavigate();

  return (
    <div>
      <h2>רשימת לקוחות</h2>
      <ul>
        {MOCK_CLIENTS.map(client => (
          <li key={client.id}>
            <button onClick={() => navigate(`/client/${client.id}`)}>
              {client.name} {client.needsMelgaza ? '(צריך melgaza)' : ''}
            </button>
          </li>
        ))}
      </ul>
      <Link to="/create">יצירת לקוח חדש</Link>
    </div>
  );
}

// ה-App הראשי עם ה-routes
function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<ClientList />} />
        <Route path="/client/:id" element={<ClientDetail />} />
        <Route path="/create" element={<CreateClient />} />
      </Routes>
    </Router>
  );
}

export default App;
```

