  const { maxSalary, max_salary, salary, value, threshold } = req.query || {};

  const maxSalaryVal = getParamValue(req.query, ['maxSalary', 'max_salary', 'salary']);
  const valueThreshold = getParamValue(req.query, ['value', 'threshold']);

