];

// רכיב ליצירת לקוח חדש (למשל: מסך יצירת לקוח)
function CreateClient() {
  const navigate = useNavigate();

  const handleCreate = () => {
    // בדיקת דטרמיניזם: תמיד יוצר את אותו לקוח (למשל: ID 99999)
    const newClient = { id: 99999, name: 'לקוח חדש', needsMelgaza: false };
    // נשמור ב-memory (בפועל אפשר לשלוף ב-state גלובלי או localStorage)
    // כאן פשוט נעבור למסך הלקוח החדש
    navigate(`/client/${newClient.id}`);
  };

  return (
    <div>
      <h2>יצירת לקוח חדש</h2>
      <button onClick={handleCreate}>צור לקוח (למשל: ID 99999)</button>
    </div>
  );
}

// רכיב להצגת פרטי לקוח
function ClientDetail({ clientId }) {
  const client = MOCK_CLIENTS.find(c => c.id === clientId);

  if (!client) {
