      <p><strong>צריך מלגזה:</strong> {client.needsMelgaza ? 'כן' : 'לא'}</p>
    </div>
  );
}

// דף הבית – מציג רשימת לקוחות
function ClientList() {
  const navigate = useNavigate();

  return (
    <div>
      <h2>רשימת לקוחות</h2>
      <ul>
        {MOCK_CLIENTS.map(client => (
          <li key={client.id}>
            <button onClick={() => navigate(`/client/${client.id}`)}>
              {client.name} {client.needsMelgaza ? '(צריך melgaza)' : ''}
            </button>
          </li>
        ))}
      </ul>
      <Link to="/create">יצירת לקוח חדש</Link>
    </div>
  );
}

// ה-App הראשי עם ה-routes
function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<ClientList />} />
        <Route path="/client/:id" element={<ClientDetail />} />
        <Route path="/create" element={<CreateClient />} />
      </Routes>
    </Router>
  );
}

export default App;
