const mongoose = require('mongoose');

const userSchema = new mongoose.Schema({
  id: {
    type: String,
    required: true,
    unique: true, // שדה חידודי
    trim: true,
    lowercase: true
  },
  name: {
    type: String,
    required: true
  }
}, { timestamps: true });

// מודל
const User = mongoose.model('User', userSchema);

// דוגמה לשימוש + טיפול בשגיאות
async function createUser(id, name) {
  try {
    const user = new User({ id, name });
    await user.save();
    return user;
  } catch (err) {
    if (err.code === 11000) {
      throw new Error(`ה-ID "${id}" כבר קיים במערכת`);
    }
    throw err;
  }
}

module.exports = { User, createUser };
```

