  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob', email: 'bob@example.com' },
];

// קומפוננטה למסך הבית
function Home() {
  return (
    <div>
      <h1>דף הבית</h1>
      <Link to="/clients">לך ללקוחות</Link>
    </div>
  );
}

// קומפוננטה למסך הלקוחות (ה"קופסא הירוקה")
