  try {
    // בדיקה דטרמיניסטית – לא מבצעת בקשת רשת אמיתית
    // אם נרצה לחקות שגיאה – אפשר לשלוף בקשת רשת אמיתית או להזריק שגיאה ידנית
    // כאן נשתמש בנתוני בדיקה קבועים
