    updateAlertsBox([{ id: -1, message: "שגיאה בטעינת התראות", type: "error" }]);
  }
}

function updateAlertsBox(alerts) {
  const alertsBox = document.getElementById("alerts-box");
  if (!alertsBox) return;

  alertsBox.innerHTML = alerts
    .map(a => `<div class="alert alert-${a.type}">${a.message}</div>`)
