import React, { useState } from 'react';

function ClientFormInputs() {
  const [formData, setFormData] = useState({
    id: '',
    name: '',
    needsMelagaza: false,
  });

  const [errors, setErrors] = useState({});

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }));

    // אימות רלוונטי
    if (name === 'id' && value !== '' && isNaN(value)) {
      setErrors((prev) => ({ ...prev, id: 'ID חייב להיות מספר' }));
    } else if (name === 'id' && value === '') {
      setErrors((prev) => ({ ...prev, id: '' }));
    }

    if (name === 'name' && value.trim() === '') {
      setErrors((prev) => ({ ...prev, name: 'שם המוצר לא יכול להיות ריק' }));
    } else if (name === 'name' && value.trim() !== '') {
      setErrors((prev) => ({ ...prev, name: '' }));
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // כאן אפשר לשלוח את הבקשה
    console.log('Form submitted:', formData);
  };

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <label>
          ID:
          <input
            type="number"
            name="id"
            value={formData.id}
            onChange={handleChange}
            placeholder="למשל 66698"
          />
        </label>
        {errors.id && <span style={{ color: 'red' }}>{errors.id}</span>}
      </div>

      <div>
        <label>
          שם המוצר:
          <input
            type="text"
            name="name"
            value={formData.name}
            onChange={handleChange}
            placeholder="למשל קופסא כחולה"
          />
        </label>
        {errors.name && <span style={{ color: 'red' }}>{errors.name}</span>}
      </div>

      <div>
        <label>
          <input
            type="checkbox"
            name="needsMelagaza"
            checked={formData.needsMelagaza}
            onChange={handleChange}
          />
          צריך melagaza
        </label>
      </div>

      <button type="submit">שליחה</button>
    </form>
  );
}

export default ClientFormInputs;
```

