      />
    </div>
  );
};

// ה-App הראשי עם מסارات
const App = () => (
  <Router>
    <Routes>
      <Route path="/" element={<Home />} />
      <Route path="/client" element={<ClientPage />} />
    </Routes>
  </Router>
);

export default App;
```

