1. **משמעות המשימה**  
המשימה מבקשת להגדיר שדה `id` (או שדה אחר, כמו `code`) כ**חד-חד-ערכי (unique)** במודל של מסד נתונים – כלומר, לא יכול להיות שני פריטים עם אותו ערך בשדה הזה.  
ההקשר (66698, קופסא כחולה, צריך מלגזה) מראה שמדובר כנראה בפריט עם קוד ייחודי (66698), וצריך לוודא שלא ייווצר פריט אחר עם אותו קוד.

2. **איך פותרים אותה**  
- ניצור מודל (למשל ב-Mongoose) עם שדה `code` שמכיל את המזהה.  
- נגדיר לו `unique: true` (או נשתמש באינדקס ייחודי).  
- נוכל להוסיף בדיקה ידנית כהטיה נוספת (למשל לפני שמירה), אך ב-Mongoose `unique: true` יוצר אינדוקס שבודק את זה ברמת מסד הנתונים.  
- נטפל בשגיאות של כפילות (Error 11000 ב-MongoDB).  
- נשתמש בנתוני בדיקה קבועים (למשל `code: '66698'`) כדי לוודא שהדטרמיניסטיות עובדת.

3. **קוד**  
```javascript
const mongoose = require('mongoose');

const itemSchema = new mongoose.Schema({
  code: {
    type: String,
    required: true,
    unique: true, // יוצר אינדוקס ייחודי
    trim: true
  },
  name: {
    type: String,
    required: true
  },
  color: {
    type: String,
    required: true
  },
  needsBox: {
    type: Boolean,
    default: false
  }
}, { timestamps: true });

// אינדוקס מפורטים (למקרה שתרצו יותר שליטה)
// itemSchema.index({ code: 1 }, { unique: true });

const Item = mongoose.model('Item', itemSchema);

// דוגמה לשימוש עם בדיקת כפילות ידנית (רלוונטית רק אם לא הוגדר unique)
async function createItemSafe({ code, name, color, needsBox }) {
  try {
    // בדיקה מוקדמת (לא חובה אם unique מוגדר, אבל מומלץ למשתמשים)
    const existing = await Item.findOne({ code });
    if (existing) {
      throw new Error(`הקוד ${code} כבר קיים במערכת`);
    }

    const newItem = new Item({ code, name, color, needsBox });
    await newItem.save();
    return newItem;
  } catch (err) {
    if (err.code === 11000) {
      throw new Error(`הקוד ${code} כבר קיים (כפילות באינדוקס)`);
    }
    throw err;
  }
}

// דוגמה לנתוני בדיקה דטרמיניסטיים
async function testUniqueness() {
  try {
    // התחלה
    await Item.deleteMany({}); // לניקוי מסד בדיקה

    // יצירת פריט ראשון
    const item1 = await createItemSafe({
      code: '66698',
      name: 'קופסא כחולה',
      color: 'כחול',
      needsBox: true
    });
    console.log('נוצר:', item1.code);

    // ניסיון ליצור פריט עם אותו קוד – אמור להשליך שגיאה
    try {
      await createItemSafe({
        code: '66698',
        name: 'קופסא אדומה',
        color: 'אדום',
        needsBox: false
      });
    } catch (err) {
      console.log('שגיאה צפוייה:', err.message);
    }
  } catch (err) {
    console.error('שגיאה בבדיקה:', err.message);
  }
}

module.exports = { Item, createItemSafe, testUniqueness };
