  <div>
    <h1>דף הבית</h1>
    <Link to="/client/12345">ללקוח רגיל</Link> | <Link to="/client/78544">ללקוח 78544 (קופסא אדומה)</Link>
  </div>
);

const Client = ({ clientId }) => {
  const navigate = useNavigate();
  const isRedBoxClient = clientId === 78544;

  return (
    <div>
      <h2>דף לקוח: {clientId}</h2>
      {isRedBoxClient ? (
        <div>
