  </div>
);

const Forbidden = () => (
  <div>
    <h2>גישה נדונה</h2>
    <p>הלקוח 78544 אינו מותר לו לגשת ל"מלגזה".</p>
    <Link to="/">חזרה לדף הבית</Link>
  </div>
);

// ה-App הראשי עם מסارات
