  // נשתמש ב-ID קבוע כנתוני בדיקה
  const [clientId] = useState(78544); // דריבי: דטרמיניסטי

  return (
    <Router>
      <div>
        <nav>
          <Link to="/">בית</Link>
        </nav>

        <Routes>
          <Route path="/" element={<Home />} />
          <Route
            path="/client/:id"
            element={<Client clientId={parseInt(useParams().id, 10)} />}
          />
