          <Route path="/melgaza" element={<Melgaza />} />
          <Route path="/forbidden" element={<Forbidden />} />
        </Routes>
      </div>
    </Router>
  );
};

// הוספת useParams (היא לא נמצאת ב-React-core, אלא ב-react-router-dom)
import { useParams } from 'react-router-dom';
// נשתמש ב-App כהופעה ראשונה – אבל כדי שהקוד יעבוד, נשתמש ב-App כהופעה סופית
export default App;
