1. **משמעות המשימה**  
המשימה מבקשת להגדיר **כללים לאימות (validation rules)** לשדות בטופס – כלומר, להגדיר אילו שדות חובה (`required`), אורך מינימלי/מקסימלי (`length`), טווח ערכים (`range`), ותבנית תקנית (`regex`).  
ההקשר מתייחס לנתונים כמו `78544`, `קופסא אדומה`, `אינו צריך מלגזה` – כלומר, ייתכן שמדובר בטופס עם שדות כמו: מספר זיהוי, שם מוצר, וסימון האם יש צורך במלגזה.

2. **איך פותרים אותה**  
- ניצור React component עם טופס (למשל, עם 3 שדות: `id`, `name`, `needsLgaza`).
- נגדיר אובייקט של כללים (validation rules) לכל שדה.
- נשתמש ב-`useState` כדי לעקוב אחרי ערכי השדות והשגיאות.
- נרשום פונקציית אימות שבודקת את כל הכללים.
- נציג שגיאות אם יש.

3. **קוד**

```jsx
import React, { useState } from 'react';

const ClientValidationRules = () => {
  const [formData, setFormData] = useState({
    id: '',
    name: '',
    needsLgaza: false
  });

  const [errors, setErrors] = useState({});

  // הגדרת כללים ל validation
  const validationRules = {
    id: {
      required: true,
      length: { min: 5, max: 9 },
      regex: /^\d+$/
    },
    name: {
      required: true,
      length: { min: 2, max: 50 }
    },
    needsLgaza: {
      required: false
    }
  };

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));

    // ננקה את השגיאה של השדה הזה כשמתחילים להקליד
    if (errors[name]) {
      setErrors(prev => {
        const newErrors = { ...prev };
        delete newErrors[name];
        return newErrors;
      });
    }
  };

  const validate = () => {
    const newErrors = {};

    // בדיקת id
    if (validationRules.id.required && !formData.id.trim()) {
      newErrors.id = 'שדה זה חובה';
    } else if (formData.id && !validationRules.id.regex.test(formData.id)) {
      newErrors.id = 'יש להזין רק ספרות';
    } else if (formData.id && (
      formData.id.length < validationRules.id.length.min ||
      formData.id.length > validationRules.id.length.max
    )) {
      newErrors.id = `אורך השדה חייב להיות בין ${validationRules.id.length.min} ל-${validationRules.id.length.max} ספרות`;
    }

    // בדיקת name
    if (validationRules.name.required && !formData.name.trim()) {
      newErrors.name = 'שדה זה חובה';
    } else if (formData.name && (
      formData.name.length < validationRules.name.length.min ||
      formData.name.length > validationRules.name.length.max
    )) {
      newErrors.name = `אורך השדה חייב להיות בין ${validationRules.name.length.min} ל-${validationRules.name.length.max} תווים`;
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (validate()) {
      alert('הטופס תקין! נתונים: ' + JSON.stringify(formData));
    }
  };

  return (
    <form onSubmit={handleSubmit} style={{ padding: '20px', maxWidth: '400px' }}>
      <h3>טופס בדיקת מוצר</h3>

      <div style={{ marginBottom: '15px' }}>
        <label>
          מספר זיהוי:
          <input
            type="text"
            name="id"
            value={formData.id}
            onChange={handleChange}
            placeholder="למשל: 78544"
          />
        </label>
        {errors.id && <div style={{ color: 'red', fontSize: '0.85em' }}>{errors.id}</div>}
      </div>

      <div style={{ marginBottom: '15px' }}>
        <label>
          שם המוצר:
          <input
            type="text"
            name="name"
            value={formData.name}
            onChange={handleChange}
            placeholder="למשל: קופסא אדומה"
          />
        </label>
        {errors.name && <div style={{ color: 'red', fontSize: '0.85em' }}>{errors.name}</div>}
      </div>

      <div style={{ marginBottom: '15px' }}>
        <label>
          <input
            type="checkbox"
            name="needsLgaza"
            checked={formData.needsLgaza}
            onChange={handleChange}
          />
          {' '} necesita melgaza?
        </label>
      </div>

      <button type="submit">שליחה</button>
    </form>
  );
};

export default ClientValidationRules;
```

