```jsx
import React, { useState } from 'react';

const SignupPage = () => {
  const [employeeId, setEmployeeId] = useState('');
  const [fullName, setFullName] = useState('');
  const [hasLicense, setHasLicense] = useState(false); // default: NO
  const [errors, setErrors] = useState({});
  const [employees, setEmployees] = useState([
    { id: '12345', name: 'Alice Smith', hasLicense: true },
    { id: '54321', name: 'Bob Cohen', hasLicense: false }
  ]);

  const validate = () => {
    const newErrors = {};

    // Validate employee ID: exactly 5 digits
    if (!/^\d{5}$/.test(employeeId)) {
      newErrors.employeeId = 'the number must be with 5 digits';
    }

    // Validate full name: letters + spaces, at least 4 letters (excluding spaces)
    const nameOnlyLetters = fullName.replace(/\s/g, '');
    if (!/^[a-zA-Z\s]+$/.test(fullName) || nameOnlyLetters.length < 4) {
      newErrors.fullName = 'the name must contain minimum 4 characters';
    }

    // Check if employee already exists (by ID only)
    if (employeeId.length === 5 && !newErrors.employeeId) {
      const exists = employees.some(emp => emp.id === employeeId);
      if (exists) {
        newErrors.employeeId = 'employee already exists';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!validate()) return;

    const newEmployee = {
      id: employeeId,
      name: fullName,
      hasLicense
    };

    setEmployees(prev => [...prev, newEmployee]);
    alert('Employee created successfully!');
    // In real app: redirect or clear form
    setEmployeeId('');
    setFullName('');
    setHasLicense(false);
    setErrors({});
  };

  return (
    <div style={{ backgroundColor: '#f0f0f0', minHeight: '100vh', padding: '20px' }}>
      <h2 style={{ textAlign: 'center', fontSize: '2rem' }}>Sign Up</h2>
      <form onSubmit={handleSubmit} style={{ maxWidth: '400px', margin: '0 auto' }}>
        {/* Employee ID Field */}
        <div style={{ marginBottom: '15px' }}>
          <label style={{ display: 'block', marginBottom: '5px' }}>Employee ID (5 digits)</label>
          <input
            type="text"
            value={employeeId}
            onChange={(e) => setEmployeeId(e.target.value.replace(/\D/g, ''))}
            placeholder="Enter 5-digit ID"
            style={{ width: '100%', padding: '8px', boxSizing: 'border-box' }}
          />
          {errors.employeeId && (
            <span style={{ color: 'red', fontSize: '0.9rem' }}>{errors.employeeId}</span>
          )}
        </div>

        {/* Full Name Field */}
        <div style={{ marginBottom: '15px' }}>
          <label style={{ display: 'block', marginBottom: '5px' }}>Full Name</label>
          <input
            type="text"
            value={fullName}
            onChange={(e) => setFullName(e.target.value)}
            placeholder="Enter full name"
            style={{ width: '100%', padding: '8px', boxSizing: 'border-box' }}
          />
          {errors.fullName && (
            <span style={{ color: 'red', fontSize: '0.9rem' }}>{errors.fullName}</span>
          )}
        </div>

        {/* License Radio Buttons */}
        <div style={{ marginBottom: '15px' }}>
          <p>Has a license for the melgaza?</p>
          <label style={{ marginRight: '15px' }}>
            <input
              type="radio"
              name="license"
              value="yes"
              checked={hasLicense}
              onChange={() => setHasLicense(true)}
            />
            YES
          </label>
          <label>
            <input
              type="radio"
              name="license"
              value="no"
              checked={!hasLicense}
              onChange={() => setHasLicense(false)}
            />
            NO
          </label>
        </div>

        {/* Submit Button */}
        <button
          type="submit"
          style={{
            backgroundColor: 'blue',
            color: 'white',
            padding: '10px 20px',
            border: 'none',
            borderRadius: '10px',
            cursor: 'pointer',
            width: '100%',
            fontSize: '1rem'
          }}
        >
          Create
        </button>
      </form>
    </div>
  );
};

export default SignupPage;
```

