// AddVolunteer.js
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

export default function AddVolunteer() {
  const [title, setTitle] = useState('');
  const [location, setLocation] = useState('');
  const [description, setDescription] = useState('');
  const navigate = useNavigate();

  const validate = () => {
    if (title.length === 0 || title.length > 20) {
      alert('כותרת חייבת להיות בין 1 ל-20 תווים');
      return false;
    }
    if (!/^[a-zA-Z]+$/.test(location)) {
      alert('מיקום חייב להיות שם עיר באנגלית בלבד (ללא מספרים, רווחים או סימנים)');
      return false;
    }
    if (description.length > 200) {
      alert('תיאור חייב להיות עד 200 תווים');
      return false;
    }
    return true;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (validate()) {
      // כאן אפשר להוסיף ל-state גלובלי או לשלוח ל-backend – בבדיקה נשתמש בנתוני בדיקה
      console.log({ title, location, description });
      alert('התנדבות נוצרה!');
      navigate('/');
    }
  };

