```javascript
// db_persistence.js
const mongoose = require('mongoose');

// הגדרת ה-Schema
const courseSchema = new mongoose.Schema({
  name: {
    type: String,
    required: true,
    trim: true,
    unique: true,
    maxlength: 100
  },
  studentsCount: {
    type: Number,
    required: true,
    min: 0,
    max: 10000
  },
  startYear: {
    type: Number,
    required: true,
    min: 1900,
    max: new Date().getFullYear()
  }
}, {
  timestamps: false // לא נשתמש ב-auto timestamps כדי לשמור דטרמיניסטיות
});

// יצירת המודל
const Course = mongoose.model('Course', courseSchema);

// פונקציה ליצירת קורס עם בדיקת שגיאות
async function createCourse(name, studentsCount, startYear) {
  try {
    const course = new Course({ name, studentsCount, startYear });
    await course.validate(); // בדיקת תקינות ידנית (לפני שמירה)
    return await course.save();
  } catch (err) {
    if (err.name === 'ValidationError') {
      throw new Error('Invalid course data: ' + Object.values(err.errors).map(e => e.message).join(', '));
    } else if (err.code === 11000) {
      throw new Error(`Course "${name}" already exists.`);
    } else {
      throw err;
    }
  }
}

// נתוני בדיקה קבועים (למשל, לשליחה ל-DB ב-test)
