  { name: 'Web Development Basics', studentsCount: 30, startYear: 2024 },
  { name: 'Database Design', studentsCount: 20, startYear: 2022 }
];

// פונקציה לטעינת נתוני בדיקה (למשל, ב-test או seed)
async function seedCourses() {
  const count = await Course.countDocuments();
  if (count === 0) {
    for (const data of TEST_DATA) {
      try {
        await createCourse(data.name, data.studentsCount, data.startYear);
      } catch (err) {
        console.error('Failed to seed course:', err.message);
      }
    }
  }
}

module.exports = { Course, createCourse, seedCourses, TEST_DATA };
```

