import { useState } from 'react';

function SearchVolunteerForm({ onSearch }) {
  const [city, setCity] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    const trimmedCity = city.trim();

    if (!trimmedCity) {
      setError('יש להזין שם עיר תקין');
      alert('יש להזין שם עיר תקין');
      return;
    }

    setError('');
    onSearch(trimmedCity); // מעביר את העיר ל.component שמנהל את הניווט
  };

  return (
    <form onSubmit={handleSubmit} style={{ margin: '20px 0' }}>
      <div>
        <label htmlFor="city-input">עיר:</label>
        <input
          id="city-input"
          type="text"
          value={city}
          onChange={(e) => setCity(e.target.value)}
          placeholder="הקלד עיר"
          style={{ marginRight: '10px' }}
        />
        <button type="submit">חפש</button>
      </div>
      {error && <p style={{ color: 'red', marginTop: '5px' }}>{error}</p>}
    </form>
  );
}

export default SearchVolunteerForm;
```

