import React, { useState } from 'react';

const VolunteerForm = () => {
  const [volunteerName, setVolunteerName] = useState('');
  const [error, setError] = useState('');

  const handleChange = (e) => {
    const value = e.target.value;
    setVolunteerName(value);

    // אימות רציף – מנקה את השגיאה אם הערך הופך תקין
    if (value.length > 2) {
      setError('');
    } else if (value.length > 0) {
      setError('שם חייב להיות באורך של לפחות 3 תווים');
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (volunteerName.length <= 2) {
      setError('שם חייב להיות באורך של לפחות 3 תווים');
      return;
    }
    // כאן אפשר לשלוח את הנתונים (למשל ל-API או ל-state גלובלי)
    console.log('Name submitted:', volunteerName);
    setError('');
    setVolunteerName('');
  };

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <label htmlFor="volunteerName">שם המתנדב:</label>
        <input
          id="volunteerName"
          type="text"
          value={volunteerName}
          onChange={handleChange}
          placeholder="הקלד שם (לפחות 3 תווים)"
        />
        {error && <p style={{ color: 'red' }}>{error}</p>}
      </div>
      <button type="submit" disabled={!!error}>
        שלח
      </button>
    </form>
  );
};

export default VolunteerForm;
