import React, { useState } from 'react';

const CitySelectForm = () => {
  // רשימת ערים עם כפילויות במכוון
  const rawCities = ["תל אביב", "ירושלים", "חיפה", "תל אביב", "באר שבע", "ירושלים"];

  // יצירת רשימת ערים ייחודיות, מסודרת (דטרמיניסטי)
  const uniqueCities = [...new Set(rawCities)].sort();

  const [selectedCity, setSelectedCity] = useState("");

  const handleChange = (event) => {
    setSelectedCity(event.target.value);
  };

