const MOCK_VOLUNTEERS = [
  { id: 1, city: 'תל אביב', title: 'איסוף ציוד למתנות', description: 'איסוף ציוד למתנות לילדים' },
  { id: 2, city: 'תל אביב', title: 'הנחת ספרים', description: 'הנחת ספרים בספרייה' },
  { id: 3, city: 'ירושלים', title: 'הובלת סדנא', description: 'סדנא לילדות' },
  { id: 4, city: 'חיפה', title: 'ניקיון חוף', description: 'ניקיון חוף דרומי' },
];

// קומפוננטת עמוד ראשי
function Home() {
  const navigate = useNavigate();
  const [city, setCity] = useState('');

  const handleSearch = () => {
    if (!city.trim()) {
      alert('אנא בחר עיר תקנית');
      return;
    }
    // מעבר ל- /all עם העיר כפרמטר URL
    navigate(`/all?city=${encodeURIComponent(city)}`);
  };

  return (
    <div style={{ padding: '20px' }}>
      <h1>מערכת התנדבות</h1>
      <input
        type="text"
        placeholder="הקלד עיר"
        value={city}
        onChange={(e) => setCity(e.target.value)}
        style={{ padding: '8px', marginRight: '10px' }}
      />
      <button onClick={handleSearch} style={{ padding: '8px 16px' }}>
        חפש
      </button>
    </div>
  );
}

// קומפוננטת עמוד /all
function AllVolunteering() {
  const location = useLocation();
  const navigate = useNavigate();

  // פarses the city from the query string
  const params = new URLSearchParams(location.search);
  const city = params.get('city') || '';

  // סינון התנדבויות לפי עיר
  const filteredVolunteers = MOCK_VOLUNTEERS.filter(v => v.city === city);

  const [selectedIds, setSelectedIds] = useState(new Set());

  const toggleSelection = (id) => {
    setSelectedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const handleConfirm = () => {
    // מחיקת התנדבויות שנבחרו (במקרה אמת – שולחים ל-backend או מוחקים מה-state)
    // כאן פשוט מחזירים ל-home
    alert(`הותקנו ${selectedIds.size} התנדבויות. חזרה לעמוד הראשי.`);
    navigate('/');
  };

  return (
    <div style={{ padding: '20px' }}>
      <h2>התנדבויות בעיר: {city}</h2>
      {filteredVolunteers.length === 0 ? (
        <p>אין התנדבויות בעיר זו.</p>
      ) : (
        <ul style={{ listStyle: 'none', padding: 0 }}>
          {filteredVolunteers.map(vol => (
            <li
              key={vol.id}
              onClick={() => toggleSelection(vol.id)}
              style={{
                padding: '10px',
                margin: '5px 0',
                backgroundColor: selectedIds.has(vol.id) ? '#d4edda' : '#ffffff',
                border: '1px solid #ccc',
                cursor: 'pointer',
              }}
            >
              <strong>{vol.title}</strong>
              {selectedIds.has(vol.id) && <p style={{ margin: '5px 0 0 0', color: '#333' }}>{vol.description}</p>}
            </li>
          ))}
        </ul>
      )}
      <button
        onClick={handleConfirm}
        disabled={selectedIds.size === 0}
        style={{
          marginTop: '20px',
          padding: '10px 20px',
          backgroundColor: selectedIds.size > 0 ? '#28a745' : '#ccc',
          color: 'white',
          border: 'none',
          cursor: selectedIds.size > 0 ? 'pointer' : 'not-allowed',
        }}
      >
        אישור
      </button>
    </div>
  );
}

// מנהל ה-App
export default function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/all" element={<AllVolunteering />} />
      </Routes>
    </Router>
  );
}
