// App.js
import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';

// נתוני בדיקה קבועים – דטרמיניסטיים
const MOCK_COURSES = [
  { id: 1, title: 'React Basics', description: 'התחלה ב-React' },
  { id: 2, title: 'Node.js Intro', description: 'שרתים ב-JavaScript' },
  { id: 3, title: 'Full-Stack Project', description: 'פרויקט סיום' },
];

// רכיב להצגת רשימת הקורסים
function CoursesList() {
  return (
    <div>
      <h2>רשימת קורסים</h2>
      <ul>
        {MOCK_COURSES.map(course => (
          <li key={course.id}>
            <Link to={`/courses/${course.id}`}>
              {course.title}
            </Link>
          </li>
        ))}
      </ul>
      <Link to="/">🏠 דף הבית</Link>
    </div>
  );
}

// רכיב להצגת פרטי קורס
function CourseDetail({ match }) {
  const id = parseInt(match.params.id, 10);
  const course = MOCK_COURSES.find(c => c.id === id);

  if (!course) {
    return <p>הקורס לא נמצא.</p>;
  }

  return (
    <div>
      <h2>{course.title}</h2>
      <p>{course.description}</p>
      <Link to="/courses">← חזרה לרשימה</Link>
    </div>
  );
}

// דף הבית (הצגת כותרת)
function Home() {
  return (
    <div>
      <h1>SVCollege – מרכז למידה</h1>
      <p>בחר קורס להצגה:</p>
      <Link to="/courses">📚 צפה בקורסים</Link>
    </div>
  );
}

// מפת המסכים
export default function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/courses" element={<CoursesList />} />
        <Route path="/courses/:id" element={<CourseDetail />} />
      </Routes>
    </Router>
  );
}
```

> **הערה**: אם לא מותקן `react-router-dom`, יש להתקין:  
> `npm install react-router-dom`

4. **מלכודת נפוצה**  
- לשכוח להוסיף `key` לאלמנטים ברשימה – גורר שגיאה ב-React.  
- לשכוח להגדיר את ה-`path` ב-`Route` כ-`/courses/:id` (עם נקודותיים) – אז ה-params לא יופעלו.  
- להשתמש ב-`window.location.href` במקום ב-`Link` או `useNavigate` – זה גורם לטעינה מלאה של הדף, ולא ניווט ב-SPA.  
- לא לבדוק אם הקורס קיים ב-`CourseDetail` – יגרום לשגיאה אם משתמש יזין ID לא קיים.

5. **בדיקת תקינות**  
- ✅ נווט בין `/`, `/courses`, `/courses/1` – כל מסך מופיע כראוי.  
- ✅ הקישורים מובילים ל-URLים נכונים, והדפדפן לא מטעין מחדש.  
- ✅ אם נזין `/courses/999` – יופיע "הקורס לא נמצא".  
- ✅ כל הנתונים הם קבועים – לא תלויים ב-DB חיצוני.  
- ✅ אין שגיאות ב-consumer (למשל: `key` חסר, `undefined` ב-`map`).

