```jsx
import React, { useState } from 'react';

const StudentCountInput = () => {
  const [value, setValue] = useState('');
  const [error, setError] = useState('');

  const validate = (val) => {
    if (!val.trim()) return 'שדה חובה';
    const num = Number(val);
    if (isNaN(num)) return 'יש להזין מספר בלבד';
    if (!Number.isInteger(num)) return 'יש להזין מספר שלם';
    if (num < 1 || num > 20) return 'המספר חייב להיות בין 1 ל-20';
    return '';
  };

  const handleChange = (e) => {
    const val = e.target.value;
    // אפשר לאמת גם כאן, אבל לרוב ממתינים ל-blur או submit
    setValue(val);
    if (error) setError(validate(val)); // עדכון שגיאה אם כבר הייתה שגיאה
  };

  const handleBlur = () => {
    setError(validate(value));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const errorMsg = validate(value);
    setError(errorMsg);
    if (!errorMsg) {
      alert(`הוזן: ${value} תלמידים`);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <label>
          מספר תלמידים:
          <input
            type="text"
            value={value}
            onChange={handleChange}
            onBlur={handleBlur}
            placeholder="הכנס מספר בין 1 ל-20"
          />
        </label>
        {error && <div style={{ color: 'red' }}>{error}</div>}
      </div>
      <button type="submit">שליחה</button>
    </form>
  );
};

export default StudentCountInput;
```

4. **מלכודת נפוצה**  
- **המרה לא-מדויקת למספר**: `Number('05')` → `5`, אבל `Number('abc')` → `NaN`.  
  חשוב לבדוק `isNaN` **לאחר** ההמרה, ולא רק עם `typeof`.  
- **הפרדה בין `type="number"` לבין אימות מילולי**:  
  `type="number"` לא מונע קלט לא-שלם (למשל `1.5`) – יש צורך ב-`Number.isInteger`.  
- **העדר איפוס שגיאות**: אם המשתמש מתקן את השגיאה, חשוב לא לשכוח לאפס את השגיאה (בקוד לעיל זה קורה ב-`handleChange` רק אם כבר הייתה שגיאה – אפשר לשפר עם `useEffect` או בדיקה מפורשת).

5. **בדיקת תקינות**  
