      <button onClick={handleShowCourses}>
        הצגת כל הקורסים
      </button>

      {courses.length > 0 && (
        <ul>
          {courses.map((course) => (
            <li key={course.id}>{course.name}</li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default ClientListRender;
```

