```jsx
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

// דוגמה לנתוני בדיקה קבועים
const MOCK_USERS = [
  { id: 1, name: 'Alice', email: 'alice@example.com', password: '123456' },
  { id: 2, name: 'Bob', email: 'bob@example.com', password: 'abcdef' }
];

const UserForm = ({ mode = 'add', userToEdit }) => {
  const navigate = useNavigate();

  // מצב התוכן של הטופס
  const [formData, setFormData] = useState({
    name: userToEdit?.name || '',
    email: userToEdit?.email || '',
    password: ''
  });

  // שגיאות אימות
  const [errors, setErrors] = useState({});

  // פונקציה לעדכון ערכים
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    // ננקה את השגיאה של השדה הזה כשמתחילים להקליד
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: '' }));
    }
  };

  // אימות בסיסי
  const validate = () => {
    const newErrors = {};
    if (!formData.name.trim()) newErrors.name = 'שם הוא שדה חובה';
    if (!formData.email.trim()) {
      newErrors.email = 'אימייל הוא שדה חובה';
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
      newErrors.email = 'פורמט אימייל לא תקין';
    }
    if (mode === 'add' && !formData.password) {
      newErrors.password = 'סיסמה היא שדה חובה';
    } else if (formData.password.length < 6) {
      newErrors.password = 'סיסמה חייבת להיות באורך של לפחות 6 תווים';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  // טיפול באישור
  const handleConfirm = () => {
    if (!validate()) return;

    // לוגיקה של הוספה/עדכון (למשל: שדרוג למשתמש קיים או הוספה ל-MOCK_USERS)
    if (mode === 'add') {
      const newUser = {
        id: Date.now(),
        ...formData
      };
      MOCK_USERS.push(newUser);
    } else if (mode === 'update' && userToEdit) {
      const idx = MOCK_USERS.findIndex(u => u.id === userToEdit.id);
      if (idx !== -1) {
        MOCK_USERS[idx] = { ...MOCK_USERS[idx], ...formData };
      }
    }

    // חזרה לעמוד home
    navigate('/home');
  };

  // טיפול ביציאה
  const handleLogout = () => {
    // לוגיקת התנתקות (למשל: ניקוי token, state)
    navigate('/signin');
  };

  return (
    <div style={{ maxWidth: '400px', margin: '0 auto', padding: '20px' }}>
      <h2>{mode === 'add' ? 'הוספת משתמש' : 'עדכון משתמש'}</h2>
      <form onSubmit={(e) => { e.preventDefault(); handleConfirm(); }}>
