  // בפועל – likely fetch, אבל כאן נשתמש ב-dummy data
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (action === 'update' && !data.id) {
        reject(new Error("חסר ID לעדכון"));
      } else {
        resolve({ success: true, action });
      }
    }, 100); // דמה עיכוב
  });
}
```

